function tanggal_indo($t){$b=array(1=>'Januari','Februari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember');$h=array('Sunday'=>'Minggu','Monday'=>'Senin','Tuesday'=>'Selasa','Wednesday'=>'Rabu','Thursday'=>'Kamis','Friday'=>'Jumat','Saturday'=>'Sabtu');$s=explode('-',$t);$he=date('l',strtotime($t));$hi=$h[$he]??$he;return $hi.', '.$s[2].' '.$b[(int)$s[1]].' '.$s[0];}
