class="frame-layer"></div><?php endif; ?><div class="bg-layer"><?php if($bg_mode=='video'&&!empty($bg_yt)): ?><?php preg_match('%(?:youtube(?:-nocookie)?\.com/(?:[^/]+/.+/|(?:v|e(?:mbed)?)/|.*[?&]v=)|youtu\.be/)([^"&?/ ]{11})%i',$bg_yt,$match);$yt_id=$match[1]??$bg_yt; ?><div class="video-foreground"><iframe src="https://www.youtube.com/embed/<?= $yt_id ?>?controls=0&showinfo=0&rel=0&autoplay=1&loop=1&mute=1&playlist=<?= $yt_id ?>&enablejsapi=1" frameborder="0" allow="autoplay; encrypted-media" style="width:100%; height:100%;"></iframe></div><?php else: ?><img src="<?= $bg_img ?>" style="width:100%; height:100%; object-fit: cover;"><?php endif; ?></div><div id="bg-overlay" class="overlay-layer"></div><div class="fixed top-4 left-4 md:top-6 md:left-6 z-40 flex items-center gap-2 md:gap-3 animate__animated animate__fadeInDown"><div class="relative flex h-4 w-4 md:h-5 md:w-5 justify-center items-center"><div class="blob"></div></div><span class="text-white font-bold tracking-[0.2em] text-xs md:text-lg drop-shadow-md font-sans">LIVE</span></div><?php if($show_waktu): ?><div class="fixed top-4 right-4 md:top-6 md:right-6 z-40 text-right animate__animated animate__fadeInDown"><div class="text-2xl md:text-5xl font-cinzel text-amber-50 font-bold drop-shadow-lg leading-none" id="jam-digital">00:00</div><div class="text-[10px] md:text-sm text-gray-300 tracking-widest uppercase mt-0.5 md:mt-1 font-sans opacity-80"><?= $tanggal_sekarang ?></div></div><?php endif; ?><?php if($show_logo&&!empty($logo_src)): ?><div class="fixed <?= $show_running?'bottom-14 md:bottom-20':'bottom-4 md:bottom-6' ?> left-4 md:left-6 z-50 flex flex-row items-center gap-2 animate__animated animate__fadeInUp transition-all"><div class="border-r border-white/40 pr-2 mr-1"><span class="text-white/70 text-[8px] md:text-[10px] tracking-widest uppercase block leading-tight font-sans font-bold text-right">Supported<br>By</span></div><img src="<?= $logo_src ?>" class="h-8 md:h-12 w-auto object-contain drop-shadow-md"></div><?php endif; ?><div class="content-wrapper px-4"><div id="display-container" class="w-full max-w-7xl flex flex-col items-center justify-center min-h-[50vh]"></div></div><?php if($show_running): ?><div class="marquee-container"><div class="marquee-content text-sm md:text-xl text-amber-50 font-sans font-medium uppercase tracking-wider"><?= htmlspecialchars($running_text_full) ?></div></div><?php endif; ?><script>const guests=<?= $json_tamu ?>;const config={showKat:<?= ($config['show_kategori']??0) ?>,showLok:<?= ($config['show_lokasi']??0) ?>,sizeTamu:<?= $size_tamu_desktop ?>};
const mode='<?= $mode ?>';const eventId=<?= $event['id'] ?>;const DURASI_TAMPIL=15000;const container=document.getElementById('display-container');const bgOverlay=document.getElementById('bg-overlay');let lastCheckTime='<?= date('Y-m-d H:i:s') ?>';let currentIndex=0;let timeoutHandle;function renderGuest(g){let k=(config.showKat&&g.kategori)?`<div class="mt-2 md:mt-4 animate__animated animate__fadeInUp animate__delay-1s"><span class="px-3 py-1 md:px-5 md:py-1.5 bg-amber-500/90 text-white rounded-full text-xs md:text-lg uppercase tracking-widest font-bold shadow-lg border border-amber-300">${g.kategori}</span></div>`:'';let l=(config.showLok&&g.alamat)?`<p class="mt-3 md:mt-5 text-gray-200 font-serif-wedding text-xl md:text-3xl animate__animated animate__fadeIn animate__delay-1s floating-text px-4 break-words max-w-3xl mx-auto"><i class="fas fa-map-marker-alt mr-1.5 text-amber-500"></i> ${g.alamat}</p>`:'';return `<div id="guest-wrapper" class="w-full text-center animate__animated animate__fadeInUp"><div class="text-amber-200/90 uppercase tracking-[0.2em] md:tracking-[0.3em] mb-2 md:mb-4 font-bold text-sm md:text-xl floating-text animate__animated animate__fadeIn">Selamat Datang</div><h1 class="nama-tamu-text font-wedding font-bold my-1 md:my-2 text-white floating-text break-words px-2">${g.nama_tamu}</h1>${k}${l}</div>`;}
function init(){if(mode==='standby'){container.innerHTML='';setInterval(checkNewGuest,500);}else if(mode==='loop'){runSlideshow();}else if(mode==='specific'&&guests.length>0){showPopupGuest(guests[0]);}}function checkNewGuest(){fetch(`?action=check_new&event_id=${eventId}&last_check=${lastCheckTime}`).then(r=>r.json()).then(res=>{if(res.status==='found'){lastCheckTime=res.timestamp;showPopupGuest(res.data);}}).catch(e=>console.error(e));}function showPopupGuest(gd){if(timeoutHandle)clearTimeout(timeoutHandle);bgOverlay.classList.add('is-dark');container.innerHTML=renderGuest(gd);timeoutHandle=setTimeout(()=>{if(mode==='standby'){const w=document.getElementById('guest-wrapper');if(w){w.classList.remove('animate__fadeInUp');w.classList.add('animate__fadeOutDown');setTimeout(()=>{container.innerHTML='';bgOverlay.classList.remove('is-dark');},1000);}else{container.innerHTML='';bgOverlay.classList.remove('is-dark');}}},DURASI_TAMPIL);}function runSlideshow(){if(guests.length===0)return;bgOverlay.classList.add('is-dark');function showNext(){container.innerHTML=renderGuest(guests[currentIndex]);currentIndex++;if(currentIndex>=guests.length)currentIndex=0;setTimeout(showNext,6000);}showNext();}setInterval(()=>{const n=new Date();const el=document.getElementById('jam-digital');if(el)el.innerText=n.toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit'}).replace('.',':');},1000);init();</script></body></html>